#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::CSV;
use DateTime;

# Ouvrez le PDF et créez un objet pour le manipuler
my $pdf = PDF::API2->open('example.pdf');

# Parcourez chaque page du PDF
for my $page (1 .. $pdf->pages) {
    my $text = $pdf->page($page)->text;

    # Recherchez des informations amusantes
    if ($text =~ /Date: (\d{1,2}\/\d{1,2}\/\d{4})/) {
        print "Ah, la date de naissance de ce document est: $1\n";
    }
    if ($text =~ /Author: (.+)/) {
        print "Le créateur de ce document, c'est: $1\n";
    }
    if ($text =~ /Table: (.+)/) {
        print "Cette table contient: $1\n";
    }
}

# Sauvegardez les données trouvées dans un fichier CSV
my $csv = Text::CSV->new({ binary => 1, auto_diag => 1 });
open my $fh, '>', 'data.csv' or die "Could not open file 'data.csv' $!";
$csv->print($fh, ["Date", "Author", "Table"]);
close $fh;

print "Vous avez maintenant un fichier CSV plein de données amusantes!\n";
